class DSU:
    def __init__(self, n):
        self.parent = list(range(n))
        self.rank = [0] * n

    def find(self, i):
        if self.parent[i] == i:
            return i
        self.parent[i] = self.find(self.parent[i])
        return self.parent[i]

    def union(self, i, j):
        root_i = self.find(i)
        root_j = self.find(j)

        if root_i != root_j:
            if self.rank[root_i] < self.rank[root_j]:
                self.parent[root_i] = root_j
            elif self.rank[root_i] > self.rank[root_j]:
                self.parent[root_j] = root_i
            else:
                self.parent[root_j] = root_i
                self.rank[root_i] += 1
            return True
        return False

def boruvka_mst(num_vertices, edges):
    mst = []
    dsu = DSU(num_vertices)
    num_components = num_vertices

    if num_vertices == 0:
        return []
    if num_vertices == 1:
        return []

    while num_components > 1:
        cheapest_edge_for_component = [None] * num_vertices

        for weight, u, v in edges:
            root_u = dsu.find(u)
            root_v = dsu.find(v)

            if root_u != root_v:
                if cheapest_edge_for_component[root_u] is None or weight < cheapest_edge_for_component[root_u][0]:
                    cheapest_edge_for_component[root_u] = (weight, u, v)

                if cheapest_edge_for_component[root_v] is None or weight < cheapest_edge_for_component[root_v][0]:
                    cheapest_edge_for_component[root_v] = (weight, u, v)

        num_edges_added_in_phase = 0
        for i in range(num_vertices):
            cheapest_edge = cheapest_edge_for_component[i]
            if cheapest_edge is not None:
                weight, u, v = cheapest_edge

                # Find current roots again, as they might have changed due to other merges
                root_u = dsu.find(u)
                root_v = dsu.find(v)

                if root_u != root_v:
                    if dsu.union(root_u, root_v): # Use DSU union on the roots directly
                        mst.append((weight, u, v))
                        num_components -= 1
                        num_edges_added_in_phase += 1

        # If no edges were added in this phase and there's more than one component,
        # it means the graph is disconnected.
        if num_edges_added_in_phase == 0 and num_components > 1:
            break

    return mst
